from nova import api
from nova.types.motion_settings import MotionSettings


def _min_or_keep(value: float | None, maximum: float | None) -> float | None:
    """Clamp ``value`` to ``maximum`` if both are set, otherwise keep ``value``."""
    if value is None or maximum is None:
        return value
    return min(value, maximum)


def _clamp_joint_list(
    values: list[float] | None,
    joint_limits: list[api.models.JointLimits] | None,
    attr: str,
) -> list[float] | None:
    """Clamp a per-joint override list element-wise to the global joint maxima.

    Fields where no global maximum is available are left untouched.
    """
    if values is None or joint_limits is None:
        return values
    clamped: list[float] = []
    for i, value in enumerate(values):
        maximum = getattr(joint_limits[i], attr) if i < len(joint_limits) else None
        clamped.append(_min_or_keep(value, maximum) if maximum is not None else value)
    return clamped


def clamp_limits_override_to_global_limits(
    limits_override: api.models.LimitsOverride,
    global_limits: api.models.LimitSet | None,
) -> None:
    """Clamp a per-segment ``limits_override`` to the motion group's global max limits.

    Per-motion ``MotionSettings`` are sent to the planner as a ``limits_override`` that
    *replaces* the global limit for that segment. If a requested limit exceeds the motion
    group maximum, the planner produces a trajectory the hardware cannot realize and the
    whole trajectory gets down-scaled at execution time. Clamping each requested value to
    the corresponding global maximum prevents this while preserving intentionally lower
    per-segment limits.

    Any limit that is unset (``None``) or for which no global maximum is available is left
    untouched. The override is mutated in place.

    Args:
        limits_override: The per-segment override to clamp.
        global_limits: The motion group's global max limits (from the setup).
    """
    if global_limits is None:
        return

    tcp = global_limits.tcp
    if tcp is not None:
        limits_override.tcp_velocity_limit = _min_or_keep(
            limits_override.tcp_velocity_limit, tcp.velocity
        )
        limits_override.tcp_acceleration_limit = _min_or_keep(
            limits_override.tcp_acceleration_limit, tcp.acceleration
        )
        limits_override.tcp_jerk_limit = _min_or_keep(limits_override.tcp_jerk_limit, tcp.jerk)
        limits_override.tcp_orientation_velocity_limit = _min_or_keep(
            limits_override.tcp_orientation_velocity_limit, tcp.orientation_velocity
        )
        limits_override.tcp_orientation_acceleration_limit = _min_or_keep(
            limits_override.tcp_orientation_acceleration_limit, tcp.orientation_acceleration
        )
        limits_override.tcp_orientation_jerk_limit = _min_or_keep(
            limits_override.tcp_orientation_jerk_limit, tcp.orientation_jerk
        )

    joints = global_limits.joints
    limits_override.joint_velocity_limits = _clamp_joint_list(
        limits_override.joint_velocity_limits, joints, "velocity"
    )
    limits_override.joint_acceleration_limits = _clamp_joint_list(
        limits_override.joint_acceleration_limits, joints, "acceleration"
    )
    limits_override.joint_jerk_limits = _clamp_joint_list(
        limits_override.joint_jerk_limits, joints, "jerk"
    )


def clamp_motion_commands_to_global_limits(
    motion_commands: list[api.models.MotionCommand],
    global_limits: api.models.LimitSet | None,
) -> None:
    """Clamp every motion command's ``limits_override`` to the global max limits.

    Commands without a ``limits_override`` are skipped. Commands are mutated in place.
    """
    if global_limits is None:
        return
    for command in motion_commands:
        if command.limits_override is not None:
            clamp_limits_override_to_global_limits(command.limits_override, global_limits)


